// Calculate Availability Percentage
FUNCTION CalculateAvailability(totalTime, downtime):
 availableTime = totalTime - downtime
 availability = (availableTime / totalTime) * 100
 RETURN availability

// Calculate from MTBF and MTTR
FUNCTION AvailabilityFromMetrics(MTBF, MTTR):
 // Availability = MTBF / (MTBF + MTTR)
 availabilityRatio = MTBF / (MTBF + MTTR)
 availabilityPercent = availabilityRatio * 100
 RETURN availabilityPercent

// Calculate Downtime from SLA
FUNCTION CalculateDowntime(slaPercentage):
 hoursPerYear = 365 * 24
 downtimePercent = 100 - slaPercentage
 downtimeHours = (downtimePercent / 100) * hoursPerYear
 downtimeMinutes = downtimeHours * 60
 RETURN {"hours": downtimeHours, "minutes": downtimeMinutes}

// Example: 99.9% uptime
RESULT = CalculateDowntime(99.9)
// Returns: 8.76 hours/year
